class QueryTraceExecutionHarnessTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String EX = "urn:trace:";
	private static final IRI ALICE = VF.createIRI(EX, "alice");
	private static final IRI BOB = VF.createIRI(EX, "bob");
	private static final IRI PERSON = VF.createIRI(EX, "Person");
	private static final IRI KIND = VF.createIRI(EX, "kind");
	private static final IRI KNOWS = VF.createIRI(EX, "knows");
	private static final IRI NAME = VF.createIRI(EX, "name");
	private static final IRI LABEL = VF.createIRI(EX, "label");
	private static final int TOTAL_CASES = 512;

	private static SailRepository repository;

	@BeforeAll
	static void setUpRepository() {
		repository = new SailRepository(new MemoryStore());
		repository.init();

		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.add(ALICE, KIND, PERSON);
			connection.add(ALICE, KNOWS, BOB);
			connection.add(ALICE, LABEL, VF.createLiteral("Alice"));
			connection.add(BOB, KIND, PERSON);
			connection.add(BOB, NAME, VF.createLiteral("Bob"));
			connection.commit();
		}
	}

	@AfterAll
	static void tearDownRepository() {
		if (repository != null) {
			repository.shutDown();
		}
	}

	@Test
	void runtimeHarnessShouldGenerateExpectedMatrixSize() {
		assertThat(ExecutionCase.count()).isEqualTo(TOTAL_CASES);
	}

	@TestFactory
	Stream<DynamicTest> generatedRuntimeCombinationsShouldStayTraceable() {
		return ExecutionCase.stream()
				.map(testCase -> DynamicTest.dynamicTest(testCase.displayName(), () -> assertTraceable(testCase)));
	}

	private static void assertTraceable(ExecutionCase testCase) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			TupleQuery query = connection.prepareTupleQuery(testCase.queryString());
			String optimizedPlan = query.explain(Explanation.Level.Optimized).toString();

			QueryTrace trace = query.trace();

			assertThat(trace.isSuccess())
					.withFailMessage("trace error %s:%s%nquery:%n%s%nplan:%n%s",
							trace.getError() == null ? "<none>" : trace.getError().getCode(),
							trace.getError() == null ? "<none>" : trace.getError().getMessage(),
							testCase.queryString(),
							optimizedPlan)
					.isTrue();
			assertThat(trace.isDistinct()).isEqualTo(testCase.withWrappers);
			assertThat(trace.getLines()).isNotEmpty();
			assertThat(trace.getFrames()).isNotEmpty();

			Map<Integer, QueryTrace.Line> stepLinesByIndex = trace.getLines()
					.stream()
					.filter(line -> line.getStepIndex() >= 0)
					.collect(java.util.stream.Collectors.toMap(QueryTrace.Line::getStepIndex, line -> line));

			for (QueryTrace.Frame frame : trace.getFrames()) {
				if (frame.getLineId() != null) {
					assertThat(trace.getLines())
							.extracting(QueryTrace.Line::getId)
							.contains(frame.getLineId());
				}
				if (frame.getStepIndex() >= 0) {
					QueryTrace.Line line = stepLinesByIndex.get(frame.getStepIndex());
					assertThat(line).isNotNull();
					assertThat(frame.getLineId()).isEqualTo(line.getId());
				}
			}

			assertThat(trace.getLines()).filteredOn(line -> "values".equals(line.getKind()))
					.hasSize(testCase.hasValues() ? 1 : 0);
			assertThat(trace.getLines()).filteredOn(line -> "bind".equals(line.getKind()))
					.hasSize(testCase.hasBind() ? 1 : 0);
			assertThat(trace.getLines()).filteredOn(line -> "optionalStart".equals(line.getKind()))
					.hasSize(testCase.hasOptional() ? 1 : 0);
			assertThat(trace.getLines()).filteredOn(line -> "optionalEnd".equals(line.getKind()))
					.hasSize(testCase.hasOptional() ? 1 : 0);
			assertThat(trace.getLines()).filteredOn(line -> "minus".equals(line.getKind()))
					.hasSize(testCase.hasMinus() ? 1 : 0);
			assertThat(trace.getLines()).filteredOn(line -> "minusEnd".equals(line.getKind()))
					.hasSize(testCase.hasMinus() ? 1 : 0);
			long filterCount = trace.getLines().stream().filter(line -> "filter".equals(line.getKind())).count();
			assertThat(filterCount)
					.as(testCase.displayName())
					.isGreaterThanOrEqualTo(testCase.hasFilter() ? 1 : 0);

			if (testCase.hasValues()) {
				assertThat(trace.getLines().get(0).getKind()).isEqualTo("values");
			}
			if (testCase.hasBind() && testCase.hasMinus()) {
				assertThat(indexOfKind(trace, "bind")).isLessThan(indexOfKind(trace, "minus"));
			}
			if (testCase.hasOptional()) {
				int optionalStart = indexOfKind(trace, "optionalStart");
				int optionalEnd = indexOfKind(trace, "optionalEnd");
				assertThat(optionalStart).isLessThan(optionalEnd);
			}

			long dropCount = trace.getFrames().stream().filter(frame -> "drop".equals(frame.getEvent())).count();
			long resultCount = trace.getFrames().stream().filter(frame -> "result".equals(frame.getEvent())).count();
			if (testCase.minusMode == 2 || testCase.minusMode == 3) {
				assertThat(dropCount).isGreaterThan(0);
				assertThat(resultCount).isZero();
			} else {
				assertThat(dropCount).isZero();
				assertThat(resultCount).isGreaterThan(0);
			}
		}
	}

	private static int indexOfKind(QueryTrace trace, String kind) {
		for (int i = 0; i < trace.getLines().size(); i++) {
			if (kind.equals(trace.getLines().get(i).getKind())) {
				return i;
			}
		}
		return -1;
	}

	private static final class ExecutionCase {
		private final int valuesMode;
		private final boolean withBind;
		private final int minusMode;
		private final boolean withOptional;
		private final boolean withFilter;
		private final boolean namedProjection;
		private final boolean withWrappers;

		private ExecutionCase(int ordinal) {
			int remainder = ordinal;
			valuesMode = remainder & 0b11;
			remainder >>= 2;
			withBind = (remainder & 0b1) != 0;
			remainder >>= 1;
			minusMode = remainder & 0b11;
			remainder >>= 2;
			withOptional = (remainder & 0b1) != 0;
			remainder >>= 1;
			withFilter = (remainder & 0b1) != 0;
			remainder >>= 1;
			namedProjection = (remainder & 0b1) != 0;
			remainder >>= 1;
			withWrappers = (remainder & 0b1) != 0;
		}

		private static int count() {
			return TOTAL_CASES;
		}

		private static Stream<ExecutionCase> stream() {
			return IntStream.range(0, TOTAL_CASES).mapToObj(ExecutionCase::new);
		}

		private String displayName() {
			return "v" + valuesMode + "-b" + (withBind ? 1 : 0) + "-m" + minusMode + "-o"
					+ (withOptional ? 1 : 0) + "-f" + (withFilter ? 1 : 0) + "-p"
					+ (namedProjection ? 1 : 0) + "-w" + (withWrappers ? 1 : 0);
		}

		private boolean hasValues() {
			return valuesMode > 0;
		}

		private boolean hasBind() {
			return withBind;
		}

		private boolean hasMinus() {
			return minusMode > 0;
		}

		private boolean hasOptional() {
			return withOptional;
		}

		private boolean hasFilter() {
			return withFilter;
		}

		private String queryString() {
			StringBuilder query = new StringBuilder();
			query.append("SELECT ");
			if (withWrappers) {
				query.append("DISTINCT ");
			}
			if (namedProjection) {
				query.append("?a ?kind ?friend");
				if (withBind) {
					query.append(" ?bound");
				}
				if (withOptional) {
					query.append(" ?optionalKind");
				}
			} else {
				query.append("*");
			}
			query.append(" WHERE { ");
			appendValuesClause(query);
			query.append("?a <").append(KIND).append("> ?kind . ");
			query.append("?a <").append(KNOWS).append("> ?friend . ");
			if (withOptional) {
				query.append("OPTIONAL { ?friend <").append(KIND).append("> ?optionalKind } ");
			}
			if (withBind) {
				query.append("BIND(?friend AS ?bound) ");
			}
			appendMinusClause(query);
			if (withFilter) {
				query.append("FILTER(BOUND(?friend)) ");
			}
			query.append("}");
			if (withWrappers) {
				query.append(" LIMIT 5");
			}
			return query.toString();
		}

		private void appendValuesClause(StringBuilder query) {
			switch (valuesMode) {
			case 1:
				query.append("VALUES ?a { <").append(ALICE).append("> } ");
				break;
			case 2:
				query.append("VALUES ?a { <").append(ALICE).append("> <").append(BOB).append("> } ");
				break;
			case 3:
				query.append("VALUES (?a ?kind) { (<")
						.append(ALICE)
						.append("> <")
						.append(PERSON)
						.append(">) (<")
						.append(BOB)
						.append("> <")
						.append(PERSON)
						.append(">) } ");
				break;
			default:
				break;
			}
		}

		private void appendMinusClause(StringBuilder query) {
			switch (minusMode) {
			case 1:
				query.append("MINUS { ?a <").append(NAME).append("> ?minusName } ");
				break;
			case 2:
				query.append("MINUS { ?friend <").append(NAME).append("> ?minusName } ");
				break;
			case 3:
				query.append("MINUS { ?friend <")
						.append(NAME)
						.append("> ?minusName . ?friend <")
						.append(KIND)
						.append("> ?minusKind } ");
				break;
			default:
				break;
			}
		}
	}
}
